<template><view class="page"><view class="intro"><text class="eyebrow">BRAND VISUAL</text><text class="title">品牌视觉实验室</text><text class="desc">为候选名字创建 Logo 与品牌板概念。当前为前端演示任务。</text></view><view class="form"><text>品牌名称</text><input v-model="form.name" placeholder="输入候选名字"/><text>视觉风格</text><picker :range="styles" @change="form.style=styles[$event.detail.value]"><view class="picker">{{form.style}}⌄</view></picker><text>主色倾向</text><view class="colors"><view v-for="color in colors" :key="color" :class="form.color===color?'active':''" @click="form.color=color">{{color}}</view></view><button :disabled="!form.name.trim()" @click="create">创建视觉概念</button></view><view class="section-head">视觉任务</view><view v-if="!items.length" class="empty">暂无视觉任务</view><view v-for="item in items" :key="item.id" class="visual"><view class="mock-logo"><text>{{item.name.slice(0,2)}}</text><text>{{item.style}}</text></view><view class="info"><view><text class="name">{{item.name}}</text><text class="status">演示完成</text></view><text class="concept">{{item.concept}}</text><text class="date">{{formatDate(item.created_at)}}</text></view></view></view></template>
<script setup>import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{createVisual,getVisuals}from'@/services/phase3Mock.js';const styles=['极简现代','东方雅致','科技未来','自然友好'];const colors=['墨绿','鎏金','海蓝','暖橙'];const form=ref({name:uni.getStorageSync('selectedName')||'',style:styles[0],color:colors[0]});const items=ref([]);onShow(()=>items.value=getVisuals());const create=()=>{if(!form.value.name.trim())return;createVisual({...form.value,name:form.value.name.trim()});items.value=getVisuals();uni.showToast({title:'视觉概念已生成',icon:'success'});};const formatDate=v=>String(v||'').replace('T',' ').slice(0,16);</script>
<style scoped>.page{min-height:100vh;padding:36rpx 30rpx 90rpx;box-sizing:border-box;color:#292620;background:#f7f4ee}.eyebrow,.title,.desc{display:block}.eyebrow{color:#8b6e40;font-size:17rpx;letter-spacing:4rpx}.title{margin-top:9rpx;font-family:serif;font-size:42rpx;font-weight:700}.desc{margin-top:10rpx;color:#938a7e;font-size:21rpx;line-height:1.6}.form{margin-top:24rpx;padding:27rpx;border-radius:22rpx;background:#fff}.form>text{display:block;margin:20rpx 0 10rpx;color:#655e55;font-size:21rpx}.form>text:first-child{margin-top:0}.form input,.picker{height:76rpx;padding:0 20rpx;line-height:76rpx;border-radius:12rpx;background:#f7f5f0}.picker{display:flex;justify-content:space-between}.colors{display:flex;gap:10rpx}.colors view{flex:1;padding:14rpx 5rpx;color:#81786c;border-radius:10rpx;background:#f3f0ea;text-align:center;font-size:19rpx}.colors .active{color:#fff;background:#4d695b}.form button{margin-top:24rpx;color:#fff;background:#3e5a4d}.section-head{margin:36rpx 4rpx 14rpx;font-size:29rpx;font-weight:700}.empty{padding:35rpx;color:#9b9286;border-radius:18rpx;background:#fff;text-align:center}.visual{display:flex;gap:20rpx;margin-top:16rpx;padding:22rpx;border-radius:20rpx;background:#fff}.mock-logo{display:flex;align-items:center;justify-content:center;flex-direction:column;width:130rpx;height:130rpx;flex-shrink:0;color:#fff;border-radius:18rpx;background:linear-gradient(135deg,#395449,#9a7952)}.mock-logo text:first-child{font-family:serif;font-size:34rpx;font-weight:700}.mock-logo text:last-child{margin-top:8rpx;font-size:16rpx}.info{flex:1}.info>view{display:flex;justify-content:space-between}.name{font-size:27rpx;font-weight:700}.status{color:#397151;font-size:18rpx}.concept,.date{display:block}.concept{margin-top:12rpx;color:#716960;font-size:20rpx;line-height:1.55}.date{margin-top:8rpx;color:#a1988b;font-size:17rpx}</style>
